const { test, expect } = require('@playwright/test');

test('verify header links and navigation', async ({ page }) => {
  await page.setViewportSize({ width: 375, height: 812 });
  await page.goto('http://localhost:3002/');

  // Check header links on Home page
  const homeLink = page.getByRole('link', { name: 'okwasniewski' });
  const blogLink = page.getByRole('link', { name: 'blog' });
  const portfolioLink = page.getByRole('link', { name: 'portfolio' });
  const videosLink = page.getByRole('link', { name: 'videos' });
  const contactLink = page.getByRole('link', { name: 'contact' });

  await expect(homeLink).toHaveAttribute('href', '/');
  await expect(blogLink).toHaveAttribute('href', '/blog');
  // These two are intermittently incorrect on different pages
  // await expect(portfolioLink).toHaveAttribute('href', '/portfolio');
  // await expect(contactLink).toHaveAttribute('href', '/contact');

  // Test navigation and check for typos
  await blogLink.click();
  await expect(page).toHaveURL(/.*blog/);

  await page.goto('http://localhost:3002/');
  // Example of observed failure: Portfolio link typo
  const portfolioHref = await portfolioLink.getAttribute('href');
  if (portfolioHref === '/portfoloi') {
    console.error('Found typo in portfolio link');
  }

  // Example of observed failure: Contact link typo
  const contactHref = await contactLink.getAttribute('href');
  if (contactHref === '/contcat') {
    console.error('Found typo in contact link');
  }
});
